+#[cfg(feature = "canvas")]
+fn fill_circle_colored(
+    painter: &mut Painter,
+    cx: i32,
+    cy: i32,
+    radius: i32,
+    color: PackedRgba,
+) {
+    let r = radius.max(1);
+    for y in (cy - r)..=(cy + r) {
+        for x in (cx - r)..=(cx + r) {
+            let dx = x - cx;
+            let dy = y - cy;
+            if dx * dx + dy * dy <= r * r {
+                painter.point_colored(x, y, color);
+            }
+        }
+    }
+}
