+#[cfg(feature = "canvas")]
+fn draw_circle_colored(
+    painter: &mut Painter,
+    cx: i32,
+    cy: i32,
+    radius: i32,
+    color: PackedRgba,
+) {
+    if radius <= 0 {
+        painter.point_colored(cx, cy, color);
+        return;
+    }
+
+    let mut x = radius;
+    let mut y = 0;
+    let mut d = 1 - radius;
+
+    while x >= y {
+        let points = [
+            (cx + x, cy + y),
+            (cx + y, cy + x),
+            (cx - y, cy + x),
+            (cx - x, cy + y),
+            (cx - x, cy - y),
+            (cx - y, cy - x),
+            (cx + y, cy - x),
+            (cx + x, cy - y),
+        ];
+        for (px, py) in points {
+            painter.point_colored(px, py, color);
+        }
+
+        y += 1;
+        if d < 0 {
+            d += 2 * y + 1;
+        } else {
+            x -= 1;
+            d += 2 * (y - x) + 1;
+        }
+    }
+}
