+#[cfg(feature = "canvas")]
+fn point_in_convex_polygon(x: i32, y: i32, points: &[(i32, i32)]) -> bool {
+    let mut sign: i32 = 0;
+    let len = points.len();
+    for i in 0..len {
+        let (x0, y0) = points[i];
+        let (x1, y1) = points[(i + 1) % len];
+        let cross = (x - x0) * (y1 - y0) - (y - y0) * (x1 - x0);
+        if cross == 0 {
+            continue;
+        }
+        let s = cross.signum();
+        if sign == 0 {
+            sign = s;
+        } else if sign != s {
+            return false;
         }
     }
+    true
 }

